export function EditItemQuantityButton({
  item,
  type,
  optimisticUpdate,
}: {
  item: CartItem;
  type: "plus" | "minus";
  optimisticUpdate: any;
}) {
  const [message, formAction] = useActionState(updateItemQuantity, null);
  const payload = {
    merchandiseId: item.merchandise.id,
    quantity: type === "plus" ? item.quantity + 1 : item.quantity - 1,
  };
  const updateItemQuantityAction = formAction.bind(null, payload);

  return (
    <form
      action={async () => {
        optimisticUpdate(payload.merchandiseId, type);
        updateItemQuantityAction();
      }}
    >
      <SubmitButton type={type} />
      <p aria-live="polite" className="sr-only" role="status">
        {message}
      </p>
    </form>
  );
}

import { useEffect, useState } from "react";
import { formatLocalDate } from "@/lib/date-format";
import { formatDistanceToNow } from "date-fns";

export default function useRelativeTime(date: Date, language?: string) {
  const [state, setState] = useState({
    fromNow: "",
    localCreatedAt: "",
  });

  // This is to avoid hydration errors when server and clients are in different timezones
  useEffect(() => {
    setState({
      fromNow: formatDistanceToNow(date, { addSuffix: true }),
      localCreatedAt: formatLocalDate(date, "PP, p", language),
    });
  }, [date, language]);

  return state;
}

function useSearchQuery() {
  const searchParams = useSearchParams();
  const searchQuery = searchParams.get("q") ?? "";
  const pathname = usePathname();
  const lastQuery = useRef(searchQuery);

  // Only update the effective search query when on the search page.
  // This prevents the query from resetting when intercepting routes
  // change the URL (e.g., opening a bookmark preview dialog).
  if (pathname.startsWith("/dashboard/search")) {
    lastQuery.current = searchQuery;
  }

  const effectiveQuery = lastQuery.current;
  const parsed = useMemo(
    () => parseSearchQuery(effectiveQuery),
    [effectiveQuery],
  );
  return { searchQuery: effectiveQuery, parsedSearchQuery: parsed };
}

export function useAssetUrl(assetId: string): AssetSource {
  const { settings } = useAppSettings();
  return {
    uri: `${settings.address}/api/assets/${assetId}`,
    headers: buildApiHeaders(settings.apiKey, settings.customHeaders),
  };
}

export function useServerVersion() {
  const { settings } = useAppSettings();

  return useQuery({
    queryKey: ["serverVersion", settings.address],
    queryFn: async () => {
      const response = await fetch(`${settings.address}/api/version`, {
        headers: buildApiHeaders(settings.apiKey, settings.customHeaders),
      });

      if (!response.ok) {
        throw new Error(`Failed to fetch server version: ${response.status}`);
      }

      const data = await response.json();
      return data.version as string;
    },
    enabled: !!settings.address,
    staleTime: 1000 * 60 * 5, // Cache for 5 minutes
  });
}

export default function Mastodon<P extends MastodonProfile>(
  options: OAuthUserConfig<P> & {
    issuer: string
  }
): OAuthConfig<P> {
  return {
    id: "mastodon",
    name: "Mastodon",
    type: "oauth",
    authorization: `${options.issuer}/oauth/authorize?scope=read`,
    token: `${options.issuer}/oauth/token`,
    userinfo: `${options.issuer}/api/v1/accounts/verify_credentials`,
    profile(profile) {
      return {
        id: profile.id,
        name: profile.username,
        image: profile.avatar_static,
        email: null,
      }
    },
    options,
  }
}

export function parseReqUrl(url: string): UrlWithParsedQuery | undefined {
  const parsedUrl: URL | undefined = parseUrl(url)

  if (!parsedUrl) {
    return
  }

  const query: Record<string, string | string[]> = {}

  for (const key of parsedUrl.searchParams.keys()) {
    const values = parsedUrl.searchParams.getAll(key)
    query[key] = values.length > 1 ? values : values[0]
  }

  const legacyUrl: UrlWithParsedQuery = {
    query,
    hash: parsedUrl.hash,
    search: parsedUrl.search,
    path: parsedUrl.pathname,
    pathname: parsedUrl.pathname,
    href: `${parsedUrl.pathname}${parsedUrl.search}${parsedUrl.hash}`,
    host: '',
    hostname: '',
    auth: '',
    protocol: '',
    slashes: null,
    port: '',
  }
  return legacyUrl
}

export function normalizedAssetPrefix(assetPrefix: string | undefined): string {
  // remove all leading slashes and trailing slashes
  const escapedAssetPrefix = assetPrefix?.replace(/^\/+|\/+$/g, '') || false

  // if an assetPrefix was '/', we return empty string
  // because it could be an unnecessary trailing slash
  if (!escapedAssetPrefix) {
    return ''
  }

  if (URL.canParse(escapedAssetPrefix)) {
    const url = new URL(escapedAssetPrefix).toString()
    return url.endsWith('/') ? url.slice(0, -1) : url
  }

  // assuming assetPrefix here is a pathname-style,
  // restore the leading slash
  return `/${escapedAssetPrefix}`
}

export function validateReceivedConfig<
  AppLocales extends Locales,
  AppLocalePrefixMode extends LocalePrefixMode,
  AppPathnames extends Pathnames<AppLocales> | undefined,
  AppDomains extends DomainsConfig<AppLocales> | undefined
>(
  config: Partial<
    Pick<
      ResolvedRoutingConfig<
        AppLocales,
        AppLocalePrefixMode,
        AppPathnames,
        AppDomains
      >,
      'defaultLocale' | 'localePrefix'
    >
  >
) {
  if (
    config.localePrefix?.mode === 'as-needed' &&
    !('defaultLocale' in config)
  ) {
    throw new Error("`localePrefix: 'as-needed' requires a `defaultLocale`.");
  }
}

function createTeamPbacProcedure(
  permission: PermissionString,
  fallbackRoles: MembershipRole[] = [MembershipRole.ADMIN, MembershipRole.OWNER]
): ReturnType<typeof authedProcedure.input> {
  return authedProcedure
    .input(
      z.object({
        teamId: z.number(),
      })
    )
    .use(async ({ ctx, input, next }) => {
      const permissionCheckService: PermissionCheckService = new PermissionCheckService();
      const hasPermission: boolean = await permissionCheckService.checkPermission({
        userId: ctx.user.id,
        teamId: input.teamId,
        permission,
        fallbackRoles,
      });

      if (!hasPermission) {
        throw new TRPCError({
          code: "FORBIDDEN",
          message: `Permission required: ${permission}`,
        });
      }

      return next();
    });
}

export function useCommand(commands: Commands = {}) {
  const [searchParams, setSearchParams] = useSearchParams();

  useEffect(() => {
    let shouldUpdate = false;
    searchParams.forEach((param, name) => {
      const commandName = name as keyof Commands;
      if (typeof commands[commandName] === "function") {
        commands[commandName]!(param);
        searchParams.delete(name);
        shouldUpdate = true;
      }
    });

    if (shouldUpdate) {
      setSearchParams(searchParams);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [searchParams, commands]);
}

